                  input  rid, rdata, rresp, rlast, rvalid, output rready);
  endinterface

  interface scrb_bus_t;
   logic [63:0]          addr;
   logic [2:0]           state;
   logic                 enable;
   logic                 done;

   modport master (input enable, output addr, state, done);

   modport slave (output enable, input addr, state, done);
